var e=JSON.parse(`[{"id":"idx_0","type":"subtitle","speaker":null,"text":{"KOREA":"CN No. VCDF001D003526-63\\n<color=#ffd34c>1급 요인</color> 열람 승인 자료\\n부록: 대상자 개인 기록 재구성","JPN":"CN No. VCDF001D003526-63\\n<color=#ffd34c>1級要因</color> 閲覧承認資料\\n付録: 対象者私記再構成","ENG":"CN No. VCDF001D003526-63\\n<color=#ffd34c>Class 1 Subject</color> Viewing Approval Material\\nAppendix: Subject Personal Record Reconstruction","TWN":"(TWN)CN No. VCDF001D003526-63\\n<color=#ffd34c>1급 요인</color> 열람 승인 자료\\n부록: 대상자 개인 기록 재구성"},"stage":{"bg":"BLACK","bgm":null,"filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"idx_1","type":"dialog","speaker":null,"text":{"KOREA":"아버지.","JPN":"父。","ENG":"Father.","TWN":"(TWN)아버지."},"stage":{"bg":"BLACK","bgm":"CUTSCENE_FLASHBACK","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"idx_2","type":"dialog","speaker":null,"text":{"KOREA":"이 시간에 웬 손님인가 했더니 너였구나, 베네딕트. 밤도 늦었는데 무슨 일이니.","JPN":"この時間になんというお客様かしたら君だったな、ベネディクト。夜も遅かったが何かだから。","ENG":"I wondered who would visit at this hour, and it was you, Benedict. It's late, what brings you here?","TWN":"(TWN)이 시간에 웬 손님인가 했더니 너였구나, 베네딕트. 밤도 늦었는데 무슨 일이니."},"stage":{"bg":"BLACK","bgm":"CUTSCENE_FLASHBACK","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"idx_3","type":"dialog","speaker":null,"text":{"KOREA":"책을 읽다가 모르는 부분이 있어서 여쭤 보려고 했습니다.","JPN":"本を読んで知らない部分があってお聞きしようとしました。","ENG":"I was reading a book and came across something I didn't understand, so I came to ask.","TWN":"(TWN)책을 읽다가 모르는 부분이 있어서 여쭤 보려고 했습니다."},"stage":{"bg":"BLACK","bgm":"CUTSCENE_FLASHBACK","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"idx_4","type":"dialog","speaker":null,"text":{"KOREA":"네 나이에 자정까지 책을 읽는 건 좋은 게 아닐 것 같구나.","JPN":"はい年齢に午前０時まで本を読むのは良いのではないようであるね。","ENG":"Reading books at your age seems like a good thing.","TWN":"(TWN)네 나이에 자정까지 책을 읽는 건 좋은 게 아닐 것 같구나."},"stage":{"bg":"BLACK","bgm":"CUTSCENE_FLASHBACK","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"idx_5","type":"dialog","speaker":null,"text":{"KOREA":"그리고 나는 네 아버지다.","JPN":"そして出る君の父だ。","ENG":"And I am your father.","TWN":"(TWN)그리고 나는 네 아버지다."},"stage":{"bg":"BLACK","bgm":"CUTSCENE_FLASHBACK","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"idx_6","type":"dialog","speaker":null,"text":{"KOREA":"딱딱하게 격식을 차리지 않아도 돼. 내가 부담을 줬는지 걱정스럽구나.","JPN":"固く格式を整えなくてもよい。私が負担を与えたのか憂わしいね。","ENG":"You don't have to stand on such ceremony. You seem worried that you've burdened me.","TWN":"(TWN)딱딱하게 격식을 차리지 않아도 돼. 내가 부담을 줬는지 걱정스럽구나."},"stage":{"bg":"BLACK","bgm":"CUTSCENE_FLASHBACK","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"idx_7","type":"dialog","speaker":null,"text":{"KOREA":"......아뇨. 아니에요. 아버지.","JPN":"......いいえ。いいえ。父。","ENG":"......No. No, Father.","TWN":"(TWN)......아뇨. 아니에요. 아버지."},"stage":{"bg":"BLACK","bgm":"CUTSCENE_FLASHBACK","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"idx_8","type":"dialog","speaker":null,"text":{"KOREA":"그래. 어차피 방으로 가도 혼자 답을 찾느라 한참 뒤척거리겠지.","JPN":"そう。どのみち部屋に行っても一人で答えを探すためにしばらく掻き回す。","ENG":"Alright. Anyway, if you went back to your room, you'd be tossing and turning alone trying to find the answer for a while.","TWN":"(TWN)그래. 어차피 방으로 가도 혼자 답을 찾느라 한참 뒤척거리겠지."},"stage":{"bg":"BLACK","bgm":"CUTSCENE_FLASHBACK","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"idx_9","type":"dialog","speaker":null,"text":{"KOREA":"같이 보자. 모르는 부분이 어떤 곳이니.","JPN":"一緒に見よう。知らない部分がどのような所だから。","ENG":"Let's look at it together. What is it you don't understand?","TWN":"(TWN)같이 보자. 모르는 부분이 어떤 곳이니."},"stage":{"bg":"BLACK","bgm":"CUTSCENE_FLASHBACK","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"idx_10","type":"dialog","speaker":null,"text":{"KOREA":"영지주의에 대해서입니다.","JPN":"領地主義に対したからです。","ENG":"It's about predestination.","TWN":"(TWN)영지주의에 대해서입니다."},"stage":{"bg":"BLACK","bgm":"CUTSCENE_FLASHBACK","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"idx_11","type":"dialog","speaker":null,"text":{"KOREA":"이단 사상 말이구나. 네게는 아직 이해하기 어려운 이야기겠지.","JPN":"異端思想言葉だな。君にはまだ理解しにくい話だろう。","ENG":"That's a difficult topic. It might be a story that's still hard for you to understand.","TWN":"(TWN)이단 사상 말이구나. 네게는 아직 이해하기 어려운 이야기겠지."},"stage":{"bg":"BLACK","bgm":"CUTSCENE_FLASHBACK","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"idx_12","type":"dialog","speaker":null,"text":{"KOREA":"영지주의는 선택된 이들만 구원 받을 수 있다고 한단다.","JPN":"領地主義は選択されたこれらだけ救援されることができると言うという。","ENG":"Predestination says that only the chosen can receive salvation.","TWN":"(TWN)영지주의는 선택된 이들만 구원 받을 수 있다고 한단다."},"stage":{"bg":"BLACK","bgm":"CUTSCENE_FLASHBACK","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"idx_13","type":"dialog","speaker":null,"text":{"KOREA":"내면의 영성을 각성한 자들만이 추악한 현실에서 벗어나 해방된 세계에 속할 수 있다는 뜻이지.","JPN":"内面の霊性を目覚めた者だけが醜悪な現実から脱して解放された世界に属すことができるという意味だ。","ENG":"It means that only those who have awakened the divinity within can escape from harsh reality and belong to the liberated world.","TWN":"(TWN)내면의 영성을 각성한 자들만이 추악한 현실에서 벗어나 해방된 세계에 속할 수 있다는 뜻이지."},"stage":{"bg":"BLACK","bgm":"CUTSCENE_FLASHBACK","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"idx_14","type":"dialog","speaker":null,"text":{"KOREA":"하지만 베네딕트, 구원의 기회는 모두에게 주어지는 것이다.","JPN":"しかしベネディクト、救援の機会は皆に与えられるのである。","ENG":"But Benedict, the opportunity for salvation is given to everyone.","TWN":"(TWN)하지만 베네딕트, 구원의 기회는 모두에게 주어지는 것이다."},"stage":{"bg":"BLACK","bgm":"CUTSCENE_FLASHBACK","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"idx_15","type":"dialog","speaker":null,"text":{"KOREA":"너나, 나나, 찬송가가 싫다고 악을 쓰는 옆집 할아버지까지.","JPN":"君や、ナナ、賛美歌が嫌いであるとわめく隣家お爺さんまで。","ENG":"To you, to me, to the hymn-singing grandmother next door who curses because she dislikes it.","TWN":"(TWN)너나, 나나, 찬송가가 싫다고 악을 쓰는 옆집 할아버지까지."},"stage":{"bg":"BLACK","bgm":"CUTSCENE_FLASHBACK","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"idx_16","type":"dialog","speaker":null,"text":{"KOREA":"현실은 벗어나야 할 곳이 아니란다. 더 아름답게 가꿀 수 있는 곳이지.","JPN":"現実は脱しなければならない所ではないそうだ。さらに美しく作ることができる所だ。","ENG":"Reality is not a place you need to escape from. It's a place you can make more beautiful.","TWN":"(TWN)현실은 벗어나야 할 곳이 아니란다. 더 아름답게 가꿀 수 있는 곳이지."},"stage":{"bg":"BLACK","bgm":"CUTSCENE_FLASHBACK","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"idx_17","type":"dialog","speaker":null,"text":{"KOREA":"간단히 말하면, 인 거죠?","JPN":"早い話が、であることですか?","ENG":"Simply put, it's free will, right?","TWN":"(TWN)간단히 말하면, 인 거죠?"},"stage":{"bg":"BLACK","bgm":"CUTSCENE_FLASHBACK","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"idx_18","type":"dialog","speaker":null,"text":{"KOREA":"그래. 간단히 말하면 그렇지.","JPN":"そう。早い話がそうなの。","ENG":"Yes. Simply put, that's right.","TWN":"(TWN)그래. 간단히 말하면 그렇지."},"stage":{"bg":"BLACK","bgm":"CUTSCENE_FLASHBACK","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"idx_19","type":"dialog","speaker":null,"text":{"KOREA":"너무 일찍, 너무 많은 것을 접하게 되면 갈피를 잡지 못하고 흔들리게 된단다. ","JPN":"とても早く、あまりにも多いのを接するようになればページを殺すことができなくて揺れるようになるという。","ENG":"If you take on too much too early, you can't hold the reins and end up shaken.","TWN":"(TWN)너무 일찍, 너무 많은 것을 접하게 되면 갈피를 잡지 못하고 흔들리게 된단다. "},"stage":{"bg":"BLACK","bgm":"CUTSCENE_FLASHBACK","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"idx_20","type":"dialog","speaker":null,"text":{"KOREA":"네가 이 아비처럼 주님의 뜻을 따르지 않아도 좋다. 하지만 바른 길을 갔으면 하는구나. ","JPN":"君がこのアビのように神様の意味に従わなくても良い。しかし正しい道に行ったらと思うのね。","ENG":"You don't have to follow the Lord's will like this father. But I hope you take the right path.","TWN":"(TWN)네가 이 아비처럼 주님의 뜻을 따르지 않아도 좋다. 하지만 바른 길을 갔으면 하는구나. "},"stage":{"bg":"BLACK","bgm":"CUTSCENE_FLASHBACK","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"idx_21","type":"dialog","speaker":null,"text":{"KOREA":"저는 아버지처럼 사제가 될 거예요.","JPN":"私はお父さんのように師弟になるはずであるです。","ENG":"I will become a priest like Father.","TWN":"(TWN)저는 아버지처럼 사제가 될 거예요."},"stage":{"bg":"BLACK","bgm":"CUTSCENE_FLASHBACK","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"idx_22","type":"dialog","speaker":null,"text":{"KOREA":"보기보다 힘든 일이란다.","JPN":"表示より大変な事だそうだ。","ENG":"It's harder than it looks.","TWN":"(TWN)보기보다 힘든 일이란다."},"stage":{"bg":"BLACK","bgm":"CUTSCENE_FLASHBACK","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"idx_23","type":"dialog","speaker":null,"text":{"KOREA":"저는 사람들을 돕고 싶어요. 아버지가 저를 도와 주신 것처럼.","JPN":"私は人々を助けたいです。お父さんが私を助けてくれたように。","ENG":"I want to save people. Just like Father helped me.","TWN":"(TWN)저는 사람들을 돕고 싶어요. 아버지가 저를 도와 주신 것처럼."},"stage":{"bg":"BLACK","bgm":"CUTSCENE_FLASHBACK","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"idx_24","type":"dialog","speaker":null,"text":{"KOREA":".......","JPN":".......","ENG":".......","TWN":"(TWN)......."},"stage":{"bg":"BLACK","bgm":"CUTSCENE_FLASHBACK","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"idx_25","type":"dialog","speaker":null,"text":{"KOREA":"밤이 깊었구나. 자, 이제 자러 가자꾸나.","JPN":"夜が深かったな。さあ、もう寝に行こう。","ENG":"The night has grown deep. Now, let's go to sleep.","TWN":"(TWN)밤이 깊었구나. 자, 이제 자러 가자꾸나."},"stage":{"bg":"BLACK","bgm":"CUTSCENE_FLASHBACK","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}}]`);export{e as default};